cssScope:
.med-report-card { font-family: sans-serif; background: #ffffff; border: 1px solid #dcdcdc; border-radius: 8px; padding: 20px; color: #2c3e50; max-width: 550px; margin: 15px 0; box-shadow: 0 4px 15px rgba(0,0,0,0.05); }
.med-header { text-align: center; border-bottom: 3px double #34495e; margin-bottom: 15px; padding-bottom: 12px; }
.med-title { font-size: 18px; font-weight: 900; color: #2c3e50; letter-spacing: 2px; }
.med-subtitle { font-size: 13px; color: #7f8c8d; margin-top: 5px; }
.med-patient-info { display: flex; flex-wrap: wrap; gap: 8px; font-size: 13px; margin-bottom: 15px; padding: 10px; background: #f8f9fa; border-radius: 4px; }
.med-patient-info span { width: 45%; font-weight: bold; }
.med-section-title { font-weight: bold; color: #2980b9; margin: 18px 0 10px; font-size: 14px; border-left: 4px solid #2980b9; padding-left: 8px; }
.med-highlight { color: #c0392b; border-left-color: #c0392b; }
.med-table { width: 100%; border-collapse: collapse; font-size: 13px; margin-bottom: 15px; }
.med-table td { border: 1px solid #e0e0e0; padding: 8px 10px; line-height: 1.4; }
.med-label { background: #ecf0f1; font-weight: bold; width: 30%; color: #34495e; }
.med-value { width: 70%; color: #333; }
.med-text-box { font-size: 13px; line-height: 1.6; padding: 12px; background: #fdfdfd; border: 1px dashed #bdc3c7; border-radius: 4px; color: #444; margin-bottom: 10px; }
.med-rx { background: #fffcf5; border-color: #f1c40f; color: #b78a00; }
.med-footer { font-size: 11px; color: #95a5a6; text-align: right; margin-top: 15px; border-top: 1px dashed #eee; padding-top: 10px; }
